%PSOGSA source code v2.0, Generated by SeyedAli Mirjalili, 2011.
%Adopted from: S. Mirjalili, S.Z. Mohd Hashim, “A New Hybrid PSOGSA
%Algorithm for Function Optimization, in IEEE International Conference
%on Computer and Information Application?ICCIA 2010), China, 2010, pp.374-377.

% This function calculates the value of objective function.
function [fit, profit, cost]=benchmark_functions(L,Benchmark_Function_ID,dim,iter)

%You can insert your own objective function with a new Benchmark_Function_ID.

if Benchmark_Function_ID==0
    fit=L.^2;
end

if Benchmark_Function_ID==1
    fit=sum(L.^2);
end

if Benchmark_Function_ID==2
    fit=sum(abs(L))+prod(abs(L));
end

if Benchmark_Function_ID==3
    fit=0;
    for i=1:dim
        fit=fit+sum(L(1:i))^2;
    end
end

if Benchmark_Function_ID==4
    fit=max(abs(L));
end

if Benchmark_Function_ID==5
    fit=sum(100*(L(2:dim)-(L(1:dim-1).^2)).^2+(L(1:dim-1)-1).^2);
end

if Benchmark_Function_ID==6
    fit=sum(abs((L+.5)).^2);
end

if Benchmark_Function_ID==7
    fit=sum([1:dim].*(L.^4))+rand;
end

if Benchmark_Function_ID==8
    fit=sum(-L.*sin(sqrt(abs(L))));
end

if Benchmark_Function_ID==9
    fit=sum(L.^2-10*cos(2*pi.*L))+10*dim;
end

if Benchmark_Function_ID==10
    fit=-20*exp(-.2*sqrt(sum(L.^2)/dim))-exp(sum(cos(2*pi.*L))/dim)+20+exp(1);
end

if Benchmark_Function_ID==11
    fit=sum(L.^2)/4000-prod(cos(L./sqrt([1:dim])))+1;
end

if Benchmark_Function_ID==12
    fit=(pi/dim)*(10*((sin(pi*(1+(L(1)+1)/4)))^2)+sum((((L(1:dim-1)+1)./4).^2).*...
        (1+10.*((sin(pi.*(1+(L(2:dim)+1)./4)))).^2))+((L(dim)+1)/4)^2)+sum(Ufun(L,10,100,4));
end
if Benchmark_Function_ID==13
    fit=.1*((sin(3*pi*L(1)))^2+sum((L(1:dim-1)-1).^2.*(1+(sin(3.*pi.*L(2:dim))).^2))+...
        ((L(dim)-1)^2)*(1+(sin(2*pi*L(dim)))^2))+sum(Ufun(L,5,100,4));
end

if Benchmark_Function_ID==14
    aS=[-32 -16 0 16 32 -32 -16 0 16 32 -32 -16 0 16 32 -32 -16 0 16 32 -32 -16 0 16 32;,...
        -32 -32 -32 -32 -32 -16 -16 -16 -16 -16 0 0 0 0 0 16 16 16 16 16 32 32 32 32 32];
    for j=1:25
        bS(j)=sum((L'-aS(:,j)).^6);
    end
    fit=(1/500+sum(1./([1:25]+bS))).^(-1);
end

if Benchmark_Function_ID==15
    aK=[.1957 .1947 .1735 .16 .0844 .0627 .0456 .0342 .0323 .0235 .0246];
    bK=[.25 .5 1 2 4 6 8 10 12 14 16];bK=1./bK;
    fit=sum((aK-((L(1).*(bK.^2+L(2).*bK))./(bK.^2+L(3).*bK+L(4)))).^2);
end

if Benchmark_Function_ID==16
    fit=4*(L(1)^2)-2.1*(L(1)^4)+(L(1)^6)/3+L(1)*L(2)-4*(L(2)^2)+4*(L(2)^4);
end

if Benchmark_Function_ID==17
    fit=(L(2)-(L(1)^2)*5.1/(4*(pi^2))+5/pi*L(1)-6)^2+10*(1-1/(8*pi))*cos(L(1))+10;
end

if Benchmark_Function_ID==18
    fit=(1+(L(1)+L(2)+1)^2*(19-14*L(1)+3*(L(1)^2)-14*L(2)+6*L(1)*L(2)+3*L(2)^2))*...
        (30+(2*L(1)-3*L(2))^2*(18-32*L(1)+12*(L(1)^2)+48*L(2)-36*L(1)*L(2)+27*(L(2)^2)));
end

if Benchmark_Function_ID==19
    aH=[3 10 30;.1 10 35;3 10 30;.1 10 35];cH=[1 1.2 3 3.2];
    pH=[.3689 .117 .2673;.4699 .4387 .747;.1091 .8732 .5547;.03815 .5743 .8828];
    fit=0;
    for i=1:4
        fit=fit-cH(i)*exp(-(sum(aH(i,:).*((L-pH(i,:)).^2))));
    end
end

if Benchmark_Function_ID==20
    aH=[10 3 17 3.5 1.7 8;.05 10 17 .1 8 14;3 3.5 1.7 10 17 8;17 8 .05 10 .1 14];
    cH=[1 1.2 3 3.2];
    pH=[.1312 .1696 .5569 .0124 .8283 .5886;.2329 .4135 .8307 .3736 .1004 .9991;...
        .2348 .1415 .3522 .2883 .3047 .6650;.4047 .8828 .8732 .5743 .1091 .0381];
    fit=0;
    for i=1:4
        fit=fit-cH(i)*exp(-(sum(aH(i,:).*((L-pH(i,:)).^2))));
    end
end

aSH=[4 4 4 4;1 1 1 1;8 8 8 8;6 6 6 6;3 7 3 7;2 9 2 9;5 5 3 3;8 1 8 1;6 2 6 2;7 3.6 7 3.6];
cSH=[.1 .2 .2 .4 .4 .6 .3 .7 .5 .5];

if Benchmark_Function_ID==21
    fit=0;
    for i=1:5
        fit=fit-((L-aSH(i,:))*(L-aSH(i,:))'+cSH(i))^(-1);
    end
end

if Benchmark_Function_ID==22
    fit=0;
    for i=1:7
        fit=fit-((L-aSH(i,:))*(L-aSH(i,:))'+cSH(i))^(-1);
    end
end

if Benchmark_Function_ID==23
    fit=0;
    for i=1:10
        fit=fit-((L-aSH(i,:))*(L-aSH(i,:))'+cSH(i))^(-1);
    end
end

if Benchmark_Function_ID==101
    data69_ga(1);
    DGnum=3;
    global errtol busnum basemva basevoltage busga linedat Slimit

    buscs1=busga;
    buscs1(:,7)=busga(:,7).*0.82;
    buscs1(:,8)=busga(:,8).*0.82;
    pf=0.9;

    no(1)=round(L(2));              sdg(1)=round(L(1)*10)/10;
    Realsize(1)=sdg(1);             buscs1(no(1),5)=Realsize(1);

    no(2)=round(L(4));              sdg(2)=round(L(3)*10)/10;
    Realsize(2)=sdg(2)*pf;          Rsize(2)=round((sqrt(sdg(2)^2-Realsize(2)^2))*10)/10;
    buscs1(no(2),5)=Realsize(2);    buscs1(no(2),6)=Rsize(2);

    no(3)=round(L(6));              sdg(3)=round(L(5)*10)/10;
    Realsize(3)=sdg(3)*pf;          Rsize(3)=-round((sqrt(sdg(3)^2-Realsize(3)^2))*10)/10;
    buscs1(no(3),5)=Realsize(3);    buscs1(no(3),6)=Rsize(3);
    rbh=L(7:20);

    [result] = gaLFThukaram(errtol, busnum, basemva, basevoltage, buscs1, linedat);
    [minV minVno]=min(result.Vm);
    [maxV maxVno]=max(result.Vm);
    ploss=sum(real(result.Lineloss));
    plri=ploss/0.1369;
    vpii=sum((result.Vm-1).^2)/0.0365;

    VA=sqrt(real(result.Sline).^2+imag(result.Sline).^2);

    Smod=1.5*Slimit;
    cii=sum(VA./Smod)/28.4778;
    %penetration limit of DG
    plimit=0.8*sum(buscs1(:,7));
    pdg=sum(Realsize);

    pload=sum(buscs1(:,7));
    pgen=pload+ploss-pdg;

    eco2=(pgen*900+Realsize(1)*40+Realsize(3)*15)/(3.2546*900);
    eso2=(pgen*1.1+Realsize(1)*0.1+Realsize(2)*0.4+Realsize(3)*0.012)/(3.2546*1.1);
    enox=(pgen*1.3+Realsize(1)*0.2+Realsize(3)*0.018)/(3.2546*1.3);
    eiri=0.5*eco2+0.25*eso2+0.25*enox;

    dgii=1-(DGnum/69);

    num1(1:3)=no(1); num2(1:3)=no(2); num3(1:3)=no(3);

    if minV < 0.94 || maxV > 1.05 || pdg > plimit || sum(num1==no)~=1 || sum(num2==no)~=1 || sum(num3==no)~=1 || sum(L==0.08)~=0 || sum(L==1.5)~=0 || sum(L(31)==1.5)~=0
        fit = 1;
    elseif VA < Smod
        fit = 0.3*plri+0.15*vpii+0.10*dgii+0.25*cii+0.20*eiri;
    else
        fit = 1;
    end

end

